/**
 * e2e/settings-page.spec.ts — Settings page E2E
 *
 * Smoke test for the settings view generated by the Native2DCompiler.
 */

import { test, expect } from '@playwright/test';

const SETTINGS_URL = '/settings';

test.describe('Settings page', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto(SETTINGS_URL, { waitUntil: 'domcontentloaded' });
  });

  test('page loads without crashing', async ({ page }) => {
    await expect(page).toHaveTitle(/HoloScript/i);
    // SettingsView should render inside the holoscript-2d-root wrapper
    await expect(page.locator('.holoscript-2d-root').first()).toBeVisible();
  });

  test('no hard JS console errors on load', async ({ page }) => {
    const errors: string[] = [];
    page.on('console', (msg) => {
      if (msg.type() === 'error') errors.push(msg.text());
    });
    await page.goto(SETTINGS_URL);
    await page.waitForLoadState('networkidle');

    const hardErrors = errors.filter(
      (e) =>
        !e.includes('WebGL') &&
        !e.includes('THREE') &&
        !e.includes('favicon') &&
        !e.includes('WebSocket') &&
        !e.includes('webpack-hmr')
    );
    expect(hardErrors).toHaveLength(0);
  });
});
